import _defineProperty from "@babel/runtime/helpers/esm/defineProperty";
import app from 'flarum/forum/app';
import UserPage from 'flarum/forum/components/UserPage';
import LoadingIndicator from 'flarum/common/components/LoadingIndicator';
import ProjectCard from './ProjectCard';
import { listProjects, likeProject } from '../../common/api';
const t = (k, p) => app.translator.trans('ernestdefoe-projects.forum.' + k, p);

/** "Projects" tab on a member's profile — their published projects as cards. */
export default class UserProjectsPage extends UserPage {
  constructor() {
    super(...arguments);
    _defineProperty(this, "projects", []);
    _defineProperty(this, "loadingProjects", true);
  }
  oninit(vnode) {
    super.oninit(vnode);
    this.loadUser(m.route.param('username'));
  }
  show(user) {
    super.show(user);
    this.loadProjects(user.id());
  }
  loadProjects(userId) {
    this.loadingProjects = true;
    listProjects({
      user: userId,
      perPage: 50
    }).then(res => {
      this.projects = res.data;
      this.loadingProjects = false;
      m.redraw();
    }).catch(() => {
      this.loadingProjects = false;
      m.redraw();
    });
  }
  like(project) {
    if (!app.session.user) return;
    likeProject(project.id).then(res => {
      const i = this.projects.findIndex(p => p.id === res.data.id);
      if (i >= 0) this.projects[i] = res.data;
      m.redraw();
    });
  }
  content() {
    if (this.loadingProjects) {
      return m('.UserProjectsPage', m(LoadingIndicator, {
        size: 'large'
      }));
    }
    if (!this.projects.length) {
      return m('.UserProjectsPage.ProjectsPage-empty', [m('i.fas.fa-cubes'), m('p', t('profile.empty'))]);
    }
    return m('.UserProjectsPage', m('.ProjectsGrid', this.projects.map(p => m(ProjectCard, {
      key: p.id,
      project: p,
      onLike: x => this.like(x)
    }))));
  }
}
flarum.reg.add('ernestdefoe-projects', 'forum/components/UserProjectsPage', UserProjectsPage);